#include <iostream>
#include <vector>
#include "euler_utils.h"
#include <cmath>
using namespace std; 
#include <gmpxx.h>


class Solution {

public:
mpz_class compute() {
mpz_class big;
mpz_class temp;
mpz_class test = 0;
mpz_class mult = 0;
mpz_class high = 0;
big = mpz_class("");
while (big > 0){    
temp = big;
mult = temp % 10;
temp /= 10;
for (int i = 0; i<=11 ; i++ ){
test = temp % 10;
temp /= 10;
mult *= test;
}
if (high < mult){high = mult;}
big /= 10;
}
return high;

}
};


int main() {
    Solution sol;
    mpz_class result;
    TIME_IT(result = sol.compute());
    cout << result << endl;
    return 0;
} 